import React from "react";
//import { FaTelegramPlane } from "react-icons/fa";
import { TiMessages } from "react-icons/ti";

function DirectContact() {
  const handleRedirect = () => {
    const telegramLink = "https://t.me/fetandesign";
    const mobileTelegramLink = "tg://resolve?domain=fetandesign";

    if (navigator.userAgent.toLowerCase().includes("mobile")) {
      // Use the mobile-specific URL scheme
      window.open(mobileTelegramLink, "_blank");
    } else {
      // Fallback for desktop browsers
      window.open(telegramLink, "_blank");
    }
  };

  return (
    <div
      className="md:hidden fixed bottom-24 right-4 flex items-center space-x-3 bg-teal-500 p-3.5 rounded-full shadow-2xl cursor-pointer transition-all transform hover:scale-110 active:scale-95 z-50 animate-bounce-subtle"
      onClick={handleRedirect}
    >
      <style>{`
        @keyframes bounce-subtle {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-5px); }
        }
        .animate-bounce-subtle {
          animation: bounce-subtle 3s infinite ease-in-out;
        }
      `}</style>
      {/* Telegram Icon with subtle glow effect */}
      <div className="relative">
        <TiMessages size={30} className="text-gray-50" />
        <span className="absolute top-0 right-0 w-3 h-3 bg-green-500 rounded-full animate-ping"></span>
      </div>
    </div>
  );
}

export default DirectContact;
